// ═══ 은행 CSV → LeanOS 포맷 변환 ═══
// 은행별 컬럼명이 다르므로 여기서 매핑합니다.
// 아래 매핑을 은행 CSV 형식에 맞게 수정하세요.

const results = [];

for (const item of items) {
  const row = item.json;

  // ── 컬럼 매핑 (은행별로 수정) ──
  // 국민은행: 거래일시, 출금액, 입금액, 거래후잔액, 적요, 거래점
  // 신한은행: 거래일, 출금, 입금, 잔액, 적요, 메모
  // 우리은행: 거래일자, 출금금액, 입금금액, 거래후잔액, 적요

  const dateStr = row['거래일시'] || row['거래일'] || row['거래일자'] || row['날짜'] || '';
  const inAmt = Number(String(row['입금액'] || row['입금'] || row['입금금액'] || '0').replace(/[^0-9.-]/g, '')) || 0;
  const outAmt = Number(String(row['출금액'] || row['출금'] || row['출금금액'] || '0').replace(/[^0-9.-]/g, '')) || 0;
  const balance = Number(String(row['거래후잔액'] || row['잔액'] || '0').replace(/[^0-9.-]/g, '')) || null;
  const counterparty = row['적요'] || row['거래처'] || row['상대'] || '';
  const memo = row['메모'] || row['비고'] || row['거래점'] || '';

  if (inAmt === 0 && outAmt === 0) continue;

  // 날짜 정규화 (YYYY-MM-DD)
  let txDate = dateStr;
  if (txDate && !txDate.includes('-')) {
    // 20260301 → 2026-03-01
    txDate = txDate.replace(/(\d{4})(\d{2})(\d{2})/, '$1-$2-$3');
  }

  results.push({
    json: {
      transaction_date: txDate,
      amount: inAmt > 0 ? inAmt : outAmt,
      balance_after: balance,
      type: inAmt > 0 ? 'income' : 'expense',
      counterparty: counterparty,
      description: memo,
      memo: '',
      raw_data: row
    }
  });
}

return results;

// 결과 로그
const result = items[0].json;
console.log(`LeanOS 전송 완료: ${result.total}건 (자동매핑: ${result.auto_mapped}, 미매핑: ${result.unmapped})`);
return items;
